import{loadPageContent,load404}from"./pages.09f9984a.js";import{loadDetailsPage}from"./components/details.4fc2da8c.js";const routes={"/":"home","/search":"search","/meet-the-creator":"portfolio"};export const handleRoute=()=>{window.scrollTo(0,0);const o=window.location.hash.substring(1)||"/",[e]=o.split("?"),t=routes[e];if(t)console.log(`Navigating to: ${t}`),loadPageContent(t);else if(o.startsWith("/details-")){const e=o.split("-")[1];console.log(`Navigating to details for: ${e}`),loadDetailsPage(e)}else load404(o)};window.addEventListener("hashchange",handleRoute),window.addEventListener("load",handleRoute);